const body = $input.first().json.body ?? $input.first().json;
    const username = (body.github_username ?? '').trim();

    if (!username) {
      // Return empty result immediately — no GitHub provided
      return [{
        json: {
          github_score: 0,
          repos: 0,
          stars: 0,
          forks: 0,
          languages: [],
          github_available: false
        }
      }];
    }

    return [{ json: { github_username: username } }];

const data = $input.first().json;
const repos = Array.isArray(data) ? data : [];

if (repos.length === 0) {
  return [{
    json: {
      github_score:     0,
      repo_count:       0,
      total_stars:      0,
      total_forks:      0,
      languages:        [],
      recently_updated: 0,
      has_descriptions: 0,
      github_available: true
    }
  }];
}

const repoCount       = repos.length;
const totalStars      = repos.reduce((s, r) => s + (r.stargazers_count ?? 0), 0);
const totalForks      = repos.reduce((s, r) => s + (r.forks_count      ?? 0), 0);
const recentlyUpdated = repos.filter(r =>
  new Date(r.updated_at) > new Date(Date.now() - 90*24*60*60*1000)
).length;
const hasDescriptions = repos.filter(r =>
  r.description && r.description.trim() !== ''
).length;

// Language diversity → curiosity proxy
const langMap = {};
for (const r of repos) {
  if (r.language) langMap[r.language] = (langMap[r.language] ?? 0) + 1;
}
const languages = Object.entries(langMap)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([lang]) => lang);

// Score: repos=40%, stars=40%, forks=20% — capped at 100
const repoScore    = Math.min((repoCount  / 20) * 40, 40);
const starScore    = Math.min((totalStars / 50) * 40, 40);
const forkScore    = Math.min((totalForks / 20) * 20, 20);
const github_score = Math.round(repoScore + starScore + forkScore);

return [{
  json: {
    github_score,
    repo_count:       repoCount,
    total_stars:      totalStars,
    total_forks:      totalForks,
    languages,
    recently_updated: recentlyUpdated,
    has_descriptions: hasDescriptions,
    github_available: true
  }
}];

const raw = $input.first().json.text
            ?? $input.first().json.response
            ?? $input.first().json.output
            ?? '';

let parsed;
try {
  const clean = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  // Safe fallback — never crash the pipeline
  return [{
    json: {
      soft_skills: {
        curiosity:     { score: 0, evidence: 'Parse error' },
        collaboration: { score: 0, evidence: 'Parse error' },
        ownership:     { score: 0, evidence: 'Parse error' },
        consistency:   { score: 0, evidence: 'Parse error' }
      },
      github_score:     $('Compute GitHub Score').first().json.github_score ?? 0,
      languages:        $('Compute GitHub Score').first().json.languages    ?? [],
      repo_count:       $('Compute GitHub Score').first().json.repo_count   ?? 0,
      summary:          '',
      github_available: true
    }
  }];
}

// Guarantee every field exists — Master Agent must never receive null
const skills = ['curiosity', 'collaboration', 'ownership', 'consistency'];
parsed.soft_skills = parsed.soft_skills ?? {};
for (const s of skills) {
  parsed.soft_skills[s]        = parsed.soft_skills[s]        ?? {};
  parsed.soft_skills[s].score  = parsed.soft_skills[s].score  ?? 0;
  parsed.soft_skills[s].evidence = parsed.soft_skills[s].evidence ?? '';
}

// Always carry forward numeric fields from NODE 5
parsed.github_score     = $('Compute GitHub Score').first().json.github_score ?? 0;
parsed.languages        = $('Compute GitHub Score').first().json.languages    ?? [];
parsed.repo_count       = $('Compute GitHub Score').first().json.repo_count   ?? 0;
parsed.github_available = true;

return [{ json: parsed }];
